    # -- FILTERED -- BSIK --
    {
        'intent': "Get filtered BSIK data",
        'business_use_case': "Retrieve BSIK with dynamic filters \u2014 BSIK + applicable parameters",
        'tables': ["BSIK"],
        'sql': "SELECT *\nFROM BSIK\nWHERE\n    BSIK.MANDT = :P_MANDT\n    -- AND BSIK.DUE.DAYS >=  :due_days  -- Days Overdue\nLIMIT 100;",
        'variant': "FILTERED",
        'module': "FI-FI",
    },

    # -- AGGREGATED -- BSIK --
    {
        'intent': "Aggregate BSIK by Vendor",
        'business_use_case': "Count and summarize BSIK records grouped by Vendor \u2014 for analytics and dashboards",
        'tables': ["BSIK"],
        'sql': "SELECT\n    BSIK.LIFNR          AS vendor,\n    COUNT(*)                       AS record_count,\n    COUNT(DISTINCT BSIK.BELNR) AS unique_records\nFROM BSIK\nWHERE BSIK.MANDT = :P_MANDT\nGROUP BY BSIK.LIFNR\nHAVING COUNT(*) > 0\nORDER BY record_count DESC\nLIMIT 100;",
        'variant': "AGGREGATED",
        'module': "FI-FI",
    },

    # -- TEMPORAL -- BSIK --
    {
        'intent': "Historical BSIK trends over time",
        'business_use_case': "Time-series aggregation of BSIK by month and fiscal year \u2014 for trend analysis",
        'tables': ["BSIK"],
        'sql': "SELECT\n    BSIK.ERSDA          AS record_date,\n    YEAR(BSIK.ERSDA)    AS fiscal_year,\n    MONTH(BSIK.ERSDA)    AS month,\n    COUNT(*)                       AS record_count\nFROM BSIK\nWHERE BSIK.MANDT = :P_MANDT\n  AND BSIK.ERSDA BETWEEN :DATE_FROM AND :DATE_TO\nGROUP BY\n    YEAR(BSIK.ERSDA),\n    MONTH(BSIK.ERSDA),\n    BSIK.ERSDA\nORDER BY fiscal_year DESC, month DESC\nLIMIT 200;",
        'variant': "TEMPORAL",
        'module': "FI-FI",
    },

